+public final class RuntimeReclamation {
+    private static final ReferenceQueue<ClassLoader> COLLECTED = new ReferenceQueue<>();
+    private static final Queue<WeakReference<ClassLoader>> TRACKED = new ConcurrentLinkedQueue<>();
+    private static final AtomicLong COLLECTED_COUNT = new AtomicLong();
+
+    private RuntimeReclamation() {
+    }
+
+    static void track(ClassLoader classLoader) {
+        reapCollected();
+        TRACKED.add(new WeakReference<>(classLoader, COLLECTED));
+    }
+
+    public static long collectedLoaders() {
+        reapCollected();
+        return COLLECTED_COUNT.get();
+    }
+
+    public static int liveLoaders() {
+        reapCollected();
+        TRACKED.removeIf(reference -> reference.get() == null);
+        return TRACKED.size();
+    }
