+    private static void reapCollected() {
+        Reference<? extends ClassLoader> reference;
+        while ((reference = COLLECTED.poll()) != null) {
+            COLLECTED_COUNT.incrementAndGet();
+            TRACKED.remove(reference);
+        }
+    }
